
        const navContainer = document.querySelector(".nav-container");
        const backToTopBtn = document.getElementById("backToTopBtn");

        window.addEventListener("scroll", function () {
            if (window.scrollY > 50) {
                navContainer.classList.add("nav-scrolled");
            } else {
                navContainer.classList.remove("nav-scrolled");
            }

            if (window.scrollY > 300) {
                backToTopBtn.style.display = "flex";
            } else {
                backToTopBtn.style.display = "none";
            }
        });

        backToTopBtn.addEventListener("click", function (e) {
            e.preventDefault();
            let targetScroll = window.scrollY - window.innerHeight;
            if (targetScroll < 0) targetScroll = 0;

            window.scrollTo({
                top: targetScroll,
                behavior: "smooth",
            });
        });

        document.addEventListener("DOMContentLoaded", () => {
            const reveals = document.querySelectorAll(".reveal");

            const revealObserver = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add("active");
                        revealObserver.unobserve(entry.target);
                    }
                });
            }, { threshold: 0.2 });

            reveals.forEach((el, index) => {
                revealObserver.observe(el);
            });

            const counters = document.querySelectorAll(".counter");
            const counterObserver = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                    if (!entry.isIntersecting) return;
                    const counter = entry.target;
                    const target = +counter.dataset.target;

                    let current = 0;
                    const increment = Math.ceil(target / 60);

                    const updateCounter = () => {
                        current += increment;
                        if (current >= target) {
                            counter.textContent = target;
                        } else {
                            counter.textContent = current;
                            requestAnimationFrame(updateCounter);
                        }
                    };

                    updateCounter();
                    counterObserver.unobserve(counter);
                });
            }, { threshold: 0.5 });

            counters.forEach(counter => counterObserver.observe(counter));
        });

        const menuLinks = document.querySelectorAll("#menuTabs .nav-link");
        const breakfastItems = document.querySelector(".breakfast-items");
        const lunchItems = document.querySelector(".lunch-items");
        const dinnerItems = document.querySelector(".dinner-items");

        function hideAllMenus() {
            if (breakfastItems) breakfastItems.style.display = "none";
            if (lunchItems) lunchItems.style.display = "none";
            if (dinnerItems) dinnerItems.style.display = "none";
        }
        menuLinks.forEach((link) => {
            link.addEventListener("click", function (e) {
                e.preventDefault();
                document.querySelector("#menuTabs .nav-link.active").classList.remove("active");
                this.classList.add("active");
                hideAllMenus();
                const text = this.innerText.trim();
                if (text.includes("Breakfast")) {
                    if (breakfastItems) breakfastItems.style.display = "flex";
                } else if (text.includes("Lunch")) {
                    if (lunchItems) lunchItems.style.display = "flex";
                } else if (text.includes("Dinner")) {
                    if (dinnerItems) dinnerItems.style.display = "flex";
                }
            });
        });
